	&lt;/li&gt;
	&lt;li data-end=&quot;1263&quot; data-start=&quot;1197&quot;&gt;
	&lt;p data-end=&quot;1263&quot; data-start=&quot;1199&quot;&gt;&lt;strong data-end=&quot;1232&quot; data-start=&quot;1199&quot;&gt;सर्वश्रेष्ठ पार्श्व गायिका (महिला)&lt;/strong&gt; - मधुबंती बागची, स्त्री 2&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1346&quot; data-start=&quot;1264&quot;&gt;
	&lt;p data-end=&quot;1346&quot; data-start=&quot;1266&quot;&gt;&lt;strong data-end=&quot;1293&quot; data-start=&quot;1266&quot;&gt;सर्वश्रेष्ठ रूपांतरित पटकथा&lt;/strong&gt; - रितेश शाह, तुषार शीतल जैन, आई वांट टू टॉक&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1393&quot; data-start=&quot;1347&quot;&gt;
	&lt;p data-end=&quot;1393&quot; data-start=&quot;1349&quot;&gt;&lt;strong data-end=&quot;1370&quot; data-start=&quot;1349&quot;&gt;सर्वश्रेष्ठ ध्वनि डिजाइन&lt;/strong&gt; - सुबाश साहू, किल&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1454&quot; data-start=&quot;1394&quot;&gt;
	&lt;p data-end=&quot;1454&quot; data-start=&quot;1396&quot;&gt;&lt;strong data-end=&quot;1421&quot; data-start=&quot;1396&quot;&gt;सर्वश्रेष्ठ पृष्ठभूमि स्कोर&lt;/strong&gt; - राम संपत, लापता लेडीज&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1509&quot; data-start=&quot;1455&quot;&gt;
	&lt;p data-end=&quot;1509&quot; data-start=&quot;1457&quot;&gt;&lt;strong data-end=&quot;1472&quot; data-start=&quot;1457&quot;&gt;सर्वश्रेष्ठ एक्शन&lt;/strong&gt; - सेयॉन्ग ओह, परवेज शेख, किल&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1560&quot; data-start=&quot;1510&quot;&gt;
	&lt;p data-end=&quot;1560&quot; data-start=&quot;1512&quot;&gt;&lt;strong data-end=&quot;1528&quot; data-start=&quot;1512&quot;&gt;सर्वश्रेष्ठ संपादन&lt;/strong&gt; - शिवकुमार वी. पणिक्कर, किल&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1610&quot; data-start=&quot;1561&quot;&gt;
	&lt;p data-end=&quot;1610&quot; data-start=&quot;1563&quot;&gt;&lt;strong data-end=&quot;1586&quot; data-start=&quot;1563&quot;&gt;सर्वश्रेष्ठ छायांकन&lt;/strong&gt; - राफे महमूद, किल&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1662&quot; data-start=&quot;1611&quot;&gt;
	&lt;p data-end=&quot;1662&quot; data-start=&quot;1613&quot;&gt;&lt;strong data-end=&quot;1639&quot; data-start=&quot;1613&quot;&gt;सर्वश्रेष्ठ उत्पादन डिजाइन&lt;/strong&gt; - मयूर शर्मा, किल&lt;/p&gt;
