	&lt;li data-end=&quot;1723&quot; data-start=&quot;1663&quot;&gt;
	&lt;p data-end=&quot;1723&quot; data-start=&quot;1665&quot;&gt;&lt;strong data-end=&quot;1688&quot; data-start=&quot;1665&quot;&gt;सर्वश्रेष्ठ कॉस्ट्यूम डिजाइन&lt;/strong&gt; - दर्शन जालान, लापता लेडीज&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1759&quot; data-start=&quot;1724&quot;&gt;
	&lt;p data-end=&quot;1759&quot; data-start=&quot;1726&quot;&gt;&lt;strong data-end=&quot;1738&quot; data-start=&quot;1726&quot;&gt;सर्वश्रेष्ठ वीएफएक्स&lt;/strong&gt; - रीडेफिन, मुंज्या&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1824&quot; data-start=&quot;1760&quot;&gt;
	&lt;p data-end=&quot;1824&quot; data-start=&quot;1762&quot;&gt;&lt;strong data-end=&quot;1783&quot; data-start=&quot;1762&quot;&gt;सर्वश्रेष्ठ कोरियोग्राफी&lt;/strong&gt; - बॉस्को-सीजर, तौबा तौबा (बैड न्यूज)&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1901&quot; data-start=&quot;1825&quot;&gt;
	&lt;p data-end=&quot;1901&quot; data-start=&quot;1827&quot;&gt;&lt;strong data-end=&quot;1857&quot; data-start=&quot;1827&quot;&gt;लाइफटाइम अचीवमेंट अवार्ड&lt;/strong&gt; - जीनत अमान, श्याम बेनेगल (मरणोपरांत)&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1988&quot; data-is-last-node=&quot;&quot; data-start=&quot;1902&quot;&gt;
	&lt;p data-end=&quot;1988&quot; data-is-last-node=&quot;&quot; data-start=&quot;1904&quot;&gt;&lt;strong data-end=&quot;1949&quot; data-start=&quot;1904&quot;&gt;आगामी संगीत प्रतिभा के लिए आरडी बर्मन पुरस्कार&lt;/strong&gt; - अचिंत ठक्कर, जिगरा, मिस्टर एंड मिसेज माही&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Manaus, Brazil&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Scientists in Brazil&amp;rsquo;s Amazon rainforest have developed AmazonFACE, a first-of-its-kind experiment designed to study how the Amazon will respond to rising CO₂ levels in the coming decades.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The experiment uses towers to release carbon dioxide into the forest canopy to simulate future atmospheric conditions.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Location:&lt;/strong&gt; Near Manaus, Brazil, deep within the Amazon rainforest.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Full Form:&lt;/strong&gt; AmazonFACE &amp;ndash; Free-Air CO₂ Enrichment.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Setup:&lt;/strong&gt; Six tower rings, each surrounding 50&amp;ndash;70 mature trees.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Objective:&lt;/strong&gt; To measure how tropical forests absorb CO₂, produce oxygen, and adapt to climate change.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Lead Institutions:&lt;/strong&gt; INPA (National Institute for Amazon Research) and Universidade Estadual de Campinas.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Support:&lt;/strong&gt; Funded jointly by Brazil and the United Kingdom.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Technology:&lt;/strong&gt; Sensors record forest response data every 10 minutes.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Significance:&lt;/strong&gt; Provides key insights into how the Amazon &amp;mdash; the &amp;ldquo;lungs of the Earth&amp;rdquo; &amp;mdash; will cope with rising CO₂ levels by 2050&amp;ndash;2060.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर है &lt;u&gt;&lt;strong&gt;मनौस, ब्राज़ील&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;समाचार में&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;ब्राजील के अमेज़न वर्षावन में वैज्ञानिकों ने AmazonFACE विकसित किया है, जो अपनी तरह का पहला प्रयोग है, जिसका उद्देश्य यह अध्ययन करना है कि आने वाले दशकों में अमेज़न बढ़ते CO₂ स्तरों पर किस प्रकार प्रतिक्रिया देगा।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;प्रमुख बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;इस प्रयोग में भविष्य की वायुमंडलीय स्थितियों का अनुकरण करने के लिए वनों में कार्बन डाइऑक्साइड छोड़ने के लिए टावरों का उपयोग किया जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;स्थान:&lt;/strong&gt; ब्राजील के मनौस के निकट, अमेज़न वर्षावन के भीतर।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;पूर्ण रूप:&lt;/strong&gt; AmazonFACE - फ्री-एयर CO₂ संवर्धन।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सेटअप:&lt;/strong&gt; छह टावर रिंग, प्रत्येक रिंग 50-70 परिपक्व पेड़ों के चारों ओर।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;उद्देश्य:&lt;/strong&gt; यह मापना कि उष्णकटिबंधीय वन किस प्रकार CO₂ को अवशोषित करते हैं, ऑक्सीजन का उत्पादन करते हैं, तथा जलवायु परिवर्तन के अनुकूल कैसे होते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;प्रमुख संस्थान:&lt;/strong&gt; INPA (नेशनल इंस्टीट्यूट फॉर अमेज़न रिसर्च) और यूनिवर्सिडेड एस्टाडुअल डी कैम्पिनास।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सहायता:&lt;/strong&gt; ब्राज़ील और यूनाइटेड किंगडम द्वारा संयुक्त रूप से वित्त पोषित।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;प्रौद्योगिकी:&lt;/strong&gt; सेंसर हर 10 मिनट में वन प्रतिक्रिया डेटा रिकॉर्ड करते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;महत्व:&lt;/strong&gt; यह इस बारे में महत्वपूर्ण जानकारी प्रदान करता है कि अमेज़न - &amp;quot;पृथ्वी के फेफड़े&amp;quot; - 2050-2060 तक बढ़ते CO₂ स्तरों का सामना कैसे करेंगे।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Nvidia&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Nvidia emerged as the world&amp;rsquo;s most valuable company in the Hurun Global 1000 Report 2025, overtaking Microsoft and Apple.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The Hurun Global 1000 Report 2025 ranks the world&amp;rsquo;s 1,000 most valuable companies&lt;/strong&gt;, expanding from the earlier Global 500 list.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Nvidia topped the rankings&lt;/strong&gt;, reflecting its sharp rise in market valuation.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The surge is driven by explosive demand for AI chips and computing power&lt;/strong&gt;, where Nvidia holds a dominant position.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The rankings highlight how AI-led innovation is reshaping global corporate leadership&lt;/strong&gt; and economic influence.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Hurun Global 1000&lt;/strong&gt; is an annual ranking that measures companies based on market capitalisation and enterprise value.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Nvidia&lt;/strong&gt; is a US-based technology company specialising in graphics processing units (GPUs) and AI hardware.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Artificial Intelligence (AI)&lt;/strong&gt; refers to computer systems capable of performing tasks that typically require human intelligence, such as learning and decision-making.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;AI chip dominance&lt;/strong&gt; has become a critical factor in determining corporate valuation due to rising demand from data centres, cloud computing, and advanced technologies.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;एनवीडिया&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;खबरों में&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;एनवीडिया हुरुन ग्लोबल 1000 रिपोर्ट 2025 में माइक्रोसॉफ्ट और एप्पल को पछाड़कर दुनिया की सबसे मूल्यवान कंपनी बन गई।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;हुरुन ग्लोबल 1000 रिपोर्ट 2025 दुनिया की 1,000 सबसे मूल्यवान कंपनियों को रैंक करती है&lt;/strong&gt;, जो पहले की ग्लोबल 500 सूची से विस्तारित है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;एनवीडिया रैंकिंग में सबसे ऊपर है&lt;/strong&gt;, जो बाजार मूल्यांकन में इसकी तेज वृद्धि को दर्शाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;यह उछाल एआई चिप्स और कंप्यूटिंग शक्ति की विस्फोटक मांग से प्रेरित है&lt;/strong&gt;, जहां एनवीडिया का दबदबा है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;रैंकिंग इस बात पर प्रकाश डालती है कि कैसे एआई-आधारित नवाचार वैश्विक कॉर्पोरेट नेतृत्व&lt;/strong&gt; और आर्थिक प्रभाव को नया आकार दे रहा है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;हुरुन ग्लोबल 1000&lt;/strong&gt; एक वार्षिक रैंकिंग है जो बाजार पूंजीकरण और उद्यम मूल्य के आधार पर कंपनियों को मापती है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;एनवीडिया&lt;/strong&gt; ग्राफिक्स प्रोसेसिंग यूनिट (जीपीयू) और एआई हार्डवेयर में विशेषज्ञता वाली एक अमेरिकी-आधारित प्रौद्योगिकी कंपनी है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;कृत्रिम बुद्धिमत्ता (एआई)&lt;/strong&gt; कंप्यूटर सिस्टम को संदर्भित करता है जो उन कार्यों को करने में सक्षम हैं जिनके लिए आमतौर पर मानव बुद्धि की आवश्यकता होती है, जैसे कि सीखना और निर्णय लेना।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;एआई चिप का प्रभुत्व&lt;/strong&gt; डेटा केंद्रों, क्लाउड कंप्यूटिंग और उन्नत प्रौद्योगिकियों से बढ़ती मांग के कारण कॉर्पोरेट मूल्यांकन निर्धारित करने में एक महत्वपूर्ण कारक बन गया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;From Roots to Global Reach: 11 Years of Transformation in Ayush.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Prime Minister Narendra Modi unveiled a book during the Second WHO Global Summit on Traditional Medicine in New Delhi.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The event took place on 19 December 2025.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The book is titled &amp;ldquo;From Roots to Global Reach: 11 Years of Transformation in Ayush&amp;rdquo;.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;It documents reforms and institutional strengthening in India&amp;rsquo;s Ayush systems.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The book highlights the global expansion of traditional Indian medicine over the past decade.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;It was unveiled alongside the WHO technical report on Yoga training.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Ayush&lt;/strong&gt;&lt;/u&gt; includes Ayurveda, Yoga, Naturopathy, Unani, Siddha, Sowa-Rigpa and Homoeopathy.&lt;/li&gt;
	&lt;li&gt;The book reflects India&amp;rsquo;s efforts to integrate traditional medicine into global health systems.&lt;/li&gt;
	&lt;li&gt;The summit was organised by the World Health Organization in collaboration with India.&lt;/li&gt;
	&lt;li&gt;Ayush systems are increasingly linked to preventive healthcare and universal health coverage.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर है &lt;u&gt;&lt;strong&gt;जड़ों से वैश्विक पहुंच तक: आयुष में 11 वर्षों का परिवर्तन।&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;समाचार में&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;प्रधान मंत्री नरेंद्र मोदी ने नई दिल्ली में पारंपरिक चिकित्सा पर दूसरे WHO वैश्विक शिखर सम्मेलन के दौरान एक पुस्तक का अनावरण किया।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;यह कार्यक्रम 19 दिसंबर 2025 को हुआ।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;पुस्तक का शीर्षक है &amp;ldquo;जड़ों से वैश्विक पहुंच तक: आयुष में 11 वर्षों का परिवर्तन&amp;rdquo;।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;यह भारत की आयुष प्रणालियों में सुधारों और संस्थागत सुदृढ़ीकरण का दस्तावेजीकरण करता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;पुस्तक पिछले एक दशक में पारंपरिक भारतीय चिकित्सा के वैश्विक विस्तार पर प्रकाश डालती है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;इसका अनावरण योग प्रशिक्षण पर WHO की तकनीकी रिपोर्ट के साथ किया गया।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align:middle;font-size:21px;&quot;&gt;&lt;u&gt;अतिरिक्त जानकारी&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;आयुष&lt;/strong&gt;&lt;/u&gt; में आयुर्वेद, योग, प्राकृतिक चिकित्सा, यूनानी, सिद्ध, सोवा-रिग्पा और होम्योपैथी शामिल हैं।&lt;/li&gt;
	&lt;li&gt;पुस्तक वैश्विक स्वास्थ्य प्रणालियों में पारंपरिक चिकित्सा को एकीकृत करने के भारत के प्रयासों को दर्शाती है।&lt;/li&gt;
	&lt;li&gt;शिखर सम्मेलन विश्व स्वास्थ्य संगठन द्वारा भारत के सहयोग से आयोजित किया गया था।&lt;/li&gt;
	&lt;li&gt;आयुष प्रणालियाँ तेजी से निवारक स्वास्थ्य सेवा और सार्वभौमिक स्वास्थ्य कवरेज से जुड़ रही हैं।&lt;/li&gt;
&lt;/ul&gt;
